    m5 = re.search(r'repeated\s+(\d+)', text, flags=re.IGNORECASE)
    if m5:
        return int(m5.group(1))
    m6 = re.search(r'\b(\d+)\b', text)
    if m6:
        # fallback: first number
        return int(m6.group(1))
